Property.Value:
RetornaCustoReceita.udp(EmpCod, ProCod) IF ProTipCus = TipoCusto.Receita;
MenorCustoFornecedor.udp(EmpCod, ProCod) IF ProTipCus = TipoCusto.MenorPreco; 
RetornaCustoUltimaCompra.udp(EmpCod, ProCod) IF ProTipCus = TipoCusto.UltimaCompra; 
RetornaCustoMedio.udp(EmpCod, 1, ProCod) IF ProTipCus = TipoCusto.CustoMedio;
RetornaCustoFixo.udp(EmpCod, ProCod) IF ProTipCus = TipoCusto.CustoFixo;
RetornaCustoFornecedorPadrao.udp(EmpCod, ProCod, ProPadForCod) IF ProTipCus = TipoCusto.FornecedorPadrao;
RetornaCustoProdutoEstoque.udp(EmpCod, ProEstProCod) IF ProTipCus = TipoCusto.CustoProdutoEstoque;
